function extractAnswer(data){if(Array.isArray(data)&&data.length>0)return data[0].answer??null;if(data.result&&Array.isArray(data.result)&&data.result.length>0)return data.result[0].answer??null;if(data.rows&&Array.isArray(data.rows)&&data.rows.length>0)return data.rows[0].answer??null;if(typeof data==='object'&&data.answer!==undefined)return data.answer;return null;}async function submitAnswer(idx){const input=document.getElementById(`input-${idx}`);const btn=document.getElementById(`btn-${idx}`);const feedback=document.getElementById(`feedback-${idx}`);const userAnswer=input.value.trim();if(!userAnswer){input.focus();return;}btn.disabled=true;input.disabled=true;feedback.className='feedback';feedback.textContent='Checking…';feedback.classList.add('show','error');try{const res=await fetch(ENDPOINTS[idx]);if(!res.ok)throw new Error(`HTTP ${res.status}`);const data=await res.json();const correctAnswer=extractAnswer(data);if(correctAnswer===null)throw new Error('Unexpected response shape');const isCorrect=userAnswer.toLowerCase()===correctAnswer.toLowerCase();feedback.className=`feedback show ${isCorrect?'correct':'incorrect'}`;feedback.textContent=isCorrect?`✓ Correct!`:`✗ Not quite — try again!`;if(!isCorrect){btn.disabled=false;input.disabled=false;input.select();}}catch(err){feedback.className='feedback show error';feedback.textContent=`Could not reach the server:${err.message}`;btn.disabled=false;input.disabled=false;}}async function submitAll(){const btn=document.getElementById('final-submit-btn');btn.disabled=true;btn.textContent='Submitting…';const payload={birthplace:document.getElementById('input-0').value.trim(),haircolour:document.getElementById('input-1').value.trim(),sport:document.getElementById('input-2').value.trim(),};try{const res=await fetch(atob('L2V4ZWMvc3VibWl0'),{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload),});if(!res.ok)throw new Error(`HTTP ${res.status}`);btn.textContent='✓ Submitted!';btn.classList.add('submitted');}catch(err){btn.textContent='Submit failed — try again';btn.disabled=false;}}document.querySelectorAll('input[type="text"]').forEach((inp,i)=>{inp.addEventListener('keydown',e=>{if(e.key==='Enter')submitAnswer(i);});});const ENDPOINTS=[atob('L2V4ZWMvc3FsP3NxbD1TRUxFQ1QlMjBhbnN3ZXIlMjBGUk9NJTIwYmlydGhwbGFjZQ=='),atob('L2V4ZWMvc3FsP3NxbD1TRUxFQ1QlMjBhbnN3ZXIlMjBGUk9NJTIwaGFpcmNvbG91cg=='),atob('L2V4ZWMvc3FsP3NxbD1TRUxFQ1QlMjBhbnN3ZXIlMjBGUk9NJTIwc3BvcnQ='),];